SELECT g.id AS goods_id, g.name AS goods_name, g.price, g.image, g.description, g.category_id, g.create_date_time, g.delete_date_time, g.is_deleted, c.name AS category_name FROM goods AS g JOIN category AS c ON g.category_id = c.id WHERE g.is_deleted = #{isDeleted}
AND g.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY c.id ASC, g.create_date_time DESC LIMIT #{limit} OFFSET #{offset}

		SELECT COUNT(*) FROM goods
		WHERE is_deleted = #{isDeleted}

            AND name LIKE CONCAT('%', #{keyword}, '%')
